  }
}

import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    environment: 'happy-dom',
    include: ['src/**/*.test.ts'],
  },
});
{
  "compilerOptions": {
    "target": "ES2022",
    "module": "ESNext",
    "moduleResolution": "Bundler",
    "strict": true,
    "outDir": "wwwroot/dist",
    "rootDir": "src",
    "sourceMap": true,
    "lib": ["ES2022", "DOM", "DOM.Iterable"],
    "esModuleInterop": true,
    "forceConsistentCasingInFileNames": true,
    "skipLibCheck": true,
    "noEmitOnError": true
  },
  "include": ["src/**/*.ts"],
  "exclude": [
    "src/**/*.test.ts",
    "src/test-utils/**",
    "src/app/test-helpers.ts",
    "node_modules",
    "wwwroot"
  ]
}

/**
 * Tests for the toolbar handlers — the search button / Enter-key handler, the
 * clear-search handler, and the upload (change) handler, including the
 * per-file upload error-handling contract.
 *
 * Split out of the former `src/app.test.ts` monolith (task-29). Shared
 * fixtures, DOM scaffolding, and the per-test fetch stub come from
 * `./test-helpers`.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 */
import { describe, it, expect, vi } from 'vitest';
import { toBrowseHash, toSearchHash } from '../router';
import { normalizeRelativePath } from '../format';
import { mockResponse } from '../test-utils/mock-response';
import { setup, flush, browseResult, fetchMock, installAppTestLifecycle } from './test-helpers';
import { clearSearch, pickAndUploadInto } from './toolbar-handlers';

installAppTestLifecycle();

/* ===========================================================================
 * Toolbar handlers
 * ========================================================================= */
describe('toolbar handlers', () => {
  describe('search', () => {
    it('navigates to a search hash 200ms after the user types in the input (debounced)', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000); // settle initial render

        searchInput.value = 'hello world';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));

        // Not yet — debounce hasn't fired
        expect(window.location.hash).toBe(toBrowseHash('docs'));

        vi.advanceTimersByTime(200);
        expect(window.location.hash).toBe(toSearchHash('hello world', 'docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('resets the debounce timer on each keystroke (only fires after 200ms of silence)', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = 'h';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(150); // not enough
        searchInput.value = 'he';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(150); // 150ms since last keystroke, still not enough
        expect(window.location.hash).toBe(toBrowseHash('docs'));

        vi.advanceTimersByTime(50); // now 200ms since last keystroke
        expect(window.location.hash).toBe(toSearchHash('he', 'docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('trims the query before navigating', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = '   spaced   ';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(200);

        expect(window.location.hash).toBe(toSearchHash('spaced', 'docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('clears the search (returns to browse) when the query becomes empty', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toSearchHash('foo', 'docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = '';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(200);

        expect(window.location.hash).toBe(toBrowseHash('docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('clears the search input and navigates to browse when the X (clear) button is clicked', async () => {
      const { searchInput, searchClearBtn } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = 'foo';
      searchClearBtn.click();

      expect(searchInput.value).toBe('');
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('clears the search input and navigates to browse when Escape is pressed', async () => {
      const { searchInput } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = 'foo';
      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));

      expect(searchInput.value).toBe('');
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('Escape key stops propagation (does not close the parent <dialog>)', async () => {
      const { searchInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      const parentEl = searchInput.closest('.file-browser') ?? document.body;
      parentEl.addEventListener('keydown', () => {
        // should NOT fire if stopPropagation worked
      });

      const event = new KeyboardEvent('keydown', { key: 'Escape', bubbles: true });
      const stopSpy = vi.spyOn(event, 'stopPropagation');
      searchInput.dispatchEvent(event);

      expect(stopSpy).toHaveBeenCalled();
    });

    it('still navigates immediately when Enter is pressed (bypasses debounce)', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = 'foo';
        searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter' }));

        // Enter fires immediately, no debounce wait needed
        expect(window.location.hash).toBe(toSearchHash('foo', 'docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('does NOT search when the query is a single character (stays on browse)', async () => {
      // A one-character (or empty) query is too short to search: doSearch falls
      // back to the browse route for the current path rather than issuing a
      // search, so the server never receives a too-short query.
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = 'h';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(200);

        expect(window.location.hash).toBe(toBrowseHash('docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('does NOT search on Enter when the query is a single character', async () => {
      // The minimum-length guard applies to Enter too: one character must not
      // issue a search even when submitted explicitly.
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = 'q';
        searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter' }));

        expect(window.location.hash).toBe(toBrowseHash('docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('searches once the query reaches two characters', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = 'he';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(200);

        expect(window.location.hash).toBe(toSearchHash('he', 'docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('clears back to browse when an existing search is edited down to one character', async () => {
      // Editing a multi-character search down below the two-character minimum
      // stops searching and returns to the browse view for the current path.
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toSearchHash('hello', 'docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = 'h';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(200);

        expect(window.location.hash).toBe(toBrowseHash('docs'));
      } finally {
        vi.useRealTimers();
      }
    });
  });

  describe('clearSearch', () => {
    // clearSearch() is the explicit "clear the search box and return to browse"
    // handler (e.g. an "×" / Clear button). It must (1) blank the shared search
    // input, (2) read the CURRENT route's path, and (3) navigate to the browse
    // hash for that path — mirroring doSearch()'s empty-query branch, but as a
    // dedicated, unconditional entry point that also wipes the input text.

    it('resets the search input value to an empty string', async () => {
      const { searchInput } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = 'leftover query';
      clearSearch();
      await flush();

      expect(searchInput.value).toBe('');
    });

    it('navigates to the browse hash for the current browse path', async () => {
      setup({ hash: toBrowseHash('docs/sub') });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash(normalizeRelativePath('docs/sub')));
    });

    it('uses the current route path even when the app is showing a search view', async () => {
      // A search route carries its own `path` (the search scope); clearSearch
      // must drop the query and return to browsing THAT path, not root.
      setup({ hash: toSearchHash('anything', 'docs') });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('normalizes the current path before building the browse hash', async () => {
      // A trailing slash (or backslashes) in the current path is collapsed by
      // normalizeRelativePath so the resulting browse hash is canonical.
      setup({ hash: toBrowseHash('docs/') });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('navigates to the root browse hash when the current path is empty', async () => {
      setup({ hash: '' });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash(''));
    });

    it('clears the input and navigates to browse together', async () => {
      const { searchInput } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = 'stale text';
      clearSearch();
      await flush();

      expect(searchInput.value).toBe('');
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });
  });

  describe('pickAndUploadInto (upload into an arbitrary folder)', () => {
    // Exercises pickAndUploadInto directly: it builds a transient
    // <input type=file multiple>, awaits its change/cancel, uploads every
    // chosen file into the GIVEN path (not the current route), then removes
    // the input and re-renders — mirroring handleUpload's contract but with a
    // caller-chosen destination.

    /** Grab the transient picker input that pickAndUploadInto appended to body. */
    function findPickerInput(): HTMLInputElement | undefined {
      // The transient input is a DIRECT child of <body>; the toolbar upload
      // input lives inside <label class="btn">, so its parent is not body.
      return Array.from(document.querySelectorAll('input[type=file]')).find(
        (i) => i.parentElement === document.body,
      ) as HTMLInputElement | undefined;
    }

    function setFiles(input: HTMLInputElement, names: string[]): void {
      const dt = new DataTransfer();
      for (const n of names) dt.items.add(new File(['data-' + n], n));
      input.files = dt.files as unknown as FileList;
    }

    const settle = async (n = 10): Promise<void> => {
      for (let i = 0; i < n; i++) await flush();
    };

    function uploadCalls(): [string, RequestInit | undefined][] {
      return fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST',
      );
    }

    it('creates a hidden <input type=file multiple> appended to body, then uploads each file into the given path', async () => {
      setup({ hash: toBrowseHash('current/dir') });
      await flush();

      // Suspend on the awaited picker: do NOT await yet.
      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      expect(pickInput, 'a transient picker input must be appended to body').toBeTruthy();
      expect(pickInput!.type).toBe('file');
      expect(pickInput!.multiple).toBe(true);

      setFiles(pickInput!, ['a.txt', 'b.txt']);
      pickInput!.dispatchEvent(new Event('change'));
      await p;
      await settle();

      // Uploads target the GIVEN path, NOT the current route.
      expect(uploadCalls()).toHaveLength(2);
      expect(
        uploadCalls().every(([u]) =>
          String(u).includes('path=' + encodeURIComponent('target/folder')),
        ),
      ).toBe(true);
      // The transient input was removed after the upload loop.
      expect(findPickerInput()).toBeUndefined();
    });

    it('uploads nothing and removes the input when the picker is cancelled (no files)', async () => {
      setup({ hash: toBrowseHash('docs') });
      await flush();

      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      expect(pickInput).toBeTruthy();

      // Dismiss the picker without choosing — the `cancel` event resolves
      // the awaited promise with an empty list.
      pickInput!.dispatchEvent(new Event('cancel'));
      await p;
      await settle();

      expect(uploadCalls()).toHaveLength(0);
      expect(findPickerInput()).toBeUndefined();
    });

    it('surfaces per-file failures in the status footer while still uploading the rest', async () => {
      fetchMock.mockImplementation(async (url: string, init?: RequestInit) => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'POST' && u.includes('/upload')) {
          const file = (init?.body as FormData | undefined)?.get('file') as File | null;
          if (file && file.name === 'bad.txt') {
            return mockResponse({ ok: false, status: 413, text: 'too large' });
          }
          return mockResponse({ status: 200, body: { path: file?.name ?? '' } });
        }
        if (method === 'GET' && u.includes('/browse')) {
          return mockResponse({ body: browseResult({ path: 'target/folder', entries: [] }) });
        }
        return mockResponse({ status: 200, body: {} });
      });
      const { status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      setFiles(pickInput!, ['good.txt', 'bad.txt']);
      pickInput!.dispatchEvent(new Event('change'));
      await p;
      await settle();

      // Both were attempted; only bad.txt is flagged.
      expect(
        uploadCalls().map(([, init]) => ((init!.body as FormData).get('file') as File).name),
      ).toEqual(['good.txt', 'bad.txt']);
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('bad.txt');
      expect(status.textContent).not.toContain('good.txt');
    });
  });
});

/**
 * Toolbar event handlers: search submission, search clearing, and upload into
 * an arbitrary folder (via the context-menu / row "Upload" action).
 *
 * They operate against the shared DOM/API context (search input value, current
 * route) and trigger a re-render via the context's render hook.
 */
import { getCurrentRoute, navigate, toBrowseHash, toSearchHash } from '../router.js';
import { normalizeRelativePath } from '../format.js';
import { getApi, getSearchInput, getStatus, rerender } from './context.js';

/**
 * Navigate to a search hash for the current input value and browse path.
 *
 * A query of fewer than two characters (after trimming) does not search: it
 * navigates to the browse route for the current path instead, so the server
 * never receives a too-short `query`. This mirrors the empty-query fallback
 * and keeps the input's text intact (only the route changes).
 */
export function doSearch(): void {
  const path = normalizeRelativePath(getCurrentRoute().path);
  const query = getSearchInput().value.trim();
  if (query.length < 2) {
    navigate(toBrowseHash(path));
    return;
  }
  navigate(toSearchHash(query, path));
}

/**
 * Clear the search input and return to the browse view for the current path.
 *
 * Resets the search input value to an empty string, reads the current path
 * (normalised), and navigates to the browse hash for that path — the same
 * behaviour as {@link doSearch} when the query is too short, but exposed as an
 * explicit, unconditional entry point that also wipes the input text.
 */
export function clearSearch(): void {
  getSearchInput().value = '';
  const path = normalizeRelativePath(getCurrentRoute().path);
  navigate(toBrowseHash(path));
}

/**
 * Open the native file picker and upload every selected file into `dirPath`
 * (an arbitrary directory, NOT necessarily the current route) — used by the
 * folder-row "Upload" and the current-directory context menus.
 *
 * Uses a self-contained, transient `<input type="file" multiple>` appended
 * hidden to body, clicked (within the menu-item click's user gesture so the
 * picker is allowed to open), awaited until either `change` (files chosen) or
 * `cancel` (dismissed), then removed — so a cancel resolves cleanly with no
 * upload and no leak. Each file is uploaded in order; per-file failures are
 * collected and surfaced in the status footer without aborting the rest.
 */
export async function pickAndUploadInto(dirPath: string): Promise<void> {
  const input = document.createElement('input');
  input.type = 'file';
  input.multiple = true;
  input.style.display = 'none';
  document.body.append(input);

  const files = await new Promise<File[]>((resolve) => {
    let settled = false;
    const finish = (list: File[]): void => {
      if (settled) {
        return;
      }
      settled = true;
      resolve(list);
    };
    input.addEventListener('change', () => {
      finish(input.files ? Array.from(input.files) : []);
    });
    // `cancel` fires when the user dismisses the picker without choosing —
    // resolve with an empty list so the input is removed and no upload runs.
    input.addEventListener('cancel', () => finish([]));
    input.click();
  });
  input.remove();

  if (files.length === 0) {
    return;
  }
  const path = normalizeRelativePath(dirPath);
  const failed: string[] = [];
  for (const file of files) {
    try {
      await getApi().upload(path, file);
    } catch {
      failed.push(file.name);
    }
  }
  await rerender();
  if (failed.length > 0) {
    const succeeded = files.length - failed.length;
    getStatus().textContent = `Uploaded ${succeeded} file(s); failed: ${failed.join(', ')}`;
  }
}

/**
 * Shared test helpers for the `src/app/*.test.ts` per-domain test files.
 *
 * Extracted verbatim from the former `src/app.test.ts` monolith (split per
 * task-29) so each focused test file can import only what it needs. Houses:
 *
 *   - fixture builders: `fileEntry`, `browseResult`, `joinPathHelper`,
 *     `browseRoute`, `searchRoute`
 *   - timing: `flush`
 *   - DOM scaffolding: `setup`, `setupCleared`, `SetupCtx`
 *   - table/row traversal: `dataRows`, `rowByName`, `cellsOf`,
 *     `clickNameLink`, `buttonsByText`
 *   - the shared per-test fetch stub lifecycle: `installAppTestLifecycle` plus
 *     the `fetchMock` live binding it rebinds each test
 *
 * `browseRoute` / `searchRoute` construct `Route` fixtures. They were
 * referenced by the dead-CSS characterization suite in the monolith but never
 * defined (a latent bug that left those tests throwing `ReferenceError`); they
 * are defined here so those scenarios finally run. `renderBrowse` /
 * `renderSearch` no longer take a `route` argument (its removal is pinned by
 * the route-independence suite), so the value is ignored at runtime — but it
 * must be a defined expression rather than a bare `ReferenceError`.
 *
 * Test-only utility: deliberately kept out of the production `tsc` build via
 * the `src/app/test-helpers.ts` entry in `tsconfig.json`'s `exclude` array
 * (mirroring the `src/test-utils/**` glob added by task-27), so it is never
 * shipped to `wwwroot/dist`. Only test files import it.
 */
import { vi, beforeEach, afterEach } from 'vitest';
import { startApp } from '../app';
import type { BrowseResult, FileEntry, SearchResult } from '../api';
import type { Route } from '../router';
import { mockResponse } from '../test-utils/mock-response';

/* ===========================================================================
 * Constants & fixture builders
 * ========================================================================= */

export const ISO = '2024-03-15T10:30:00'; // offset-free → parsed as local time
export const ISO_FMT = '2024-03-15 10:30'; // expected formatDate(...) output

export function fileEntry(opts: Partial<FileEntry> & { name: string }): FileEntry {
  return {
    name: opts.name,
    path: opts.path ?? joinPathHelper('docs', opts.name),
    isDirectory: opts.isDirectory ?? false,
    size: opts.size ?? 0,
    lastModified: opts.lastModified ?? ISO,
    itemCount: opts.itemCount ?? 0,
  };
}

export function browseResult(opts: Partial<BrowseResult> = {}): BrowseResult {
  return {
    path: opts.path ?? '',
    parent: opts.parent ?? null,
    entries: opts.entries ?? [],
    folderCount: opts.folderCount ?? 0,
    fileCount: opts.fileCount ?? 0,
    totalSize: opts.totalSize ?? 0,
  };
}

// local join to avoid pulling joinPath into the test's asserted import set
export function joinPathHelper(base: string, name: string): string {
  return (base ? base + '/' : '') + name;
}

/** Build a browse `Route` fixture. */
export function browseRoute(path: string): Route {
  return { view: 'browse', path, query: '' };
}

/** Build a search `Route` fixture. */
export function searchRoute(query: string, path: string = ''): Route {
  return { view: 'search', query, path };
}

/* ===========================================================================
 * Timing
 * ========================================================================= */

/** Let pending microtasks / queued hashchange renders settle. */
export const flush = (): Promise<void> => new Promise((r) => setTimeout(r, 0));

/* ===========================================================================
 * DOM scaffolding
 * ========================================================================= */

export interface SetupCtx {
  root: HTMLElement;
  embeddedHost: HTMLElement;
  widget: HTMLElement;
  dialog: HTMLDialogElement;
  trigger: HTMLButtonElement;
  closeBtn: HTMLButtonElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
  searchWrapper: HTMLElement;
  searchClearBtn: HTMLButtonElement;
  searchIcon: HTMLElement;
  results: HTMLElement;
  status: HTMLElement;
}

/**
 * Build a fresh app inside a fresh container. Clears `document.body` first so
 * every test is independent (no leakage of elements, and document-scoped
 * queries inside `renderBrowse`/`renderSearch` always resolve to the current
 * test's DOM).
 */
export function setup(options: { hash?: string } = {}): SetupCtx {
  document.body.innerHTML = '';
  window.location.hash = options.hash ?? '';

  const root = document.createElement('div');
  document.body.append(root);
  startApp(root);

  return {
    root,
    embeddedHost: root.querySelector('.file-browser-host') as HTMLElement,
    widget: root.querySelector('.file-browser') as HTMLElement,
    dialog: root.querySelector('dialog.browser-dialog') as HTMLDialogElement,
    trigger: root.querySelector('button.trigger') as HTMLButtonElement,
    closeBtn: root.querySelector('.close-btn') as HTMLButtonElement,
    breadcrumb: root.querySelector('.breadcrumb') as HTMLElement,
    searchInput: root.querySelector('input[type="text"]') as HTMLInputElement,
    searchWrapper: root.querySelector('.search-wrapper') as HTMLElement,
    searchClearBtn: root.querySelector('.search-wrapper .clear-btn') as HTMLButtonElement,
    searchIcon: root.querySelector('.search-wrapper .search-icon') as HTMLElement,
    results: root.querySelector('.results') as HTMLElement,
    status: root.querySelector('.status') as HTMLElement,
  };
}

/**
 * `setup()` plus a flush (so startApp's initial `render()` settles) and a clear
 * of `.results`, mimicking what `render()` does before delegating to
 * `renderBrowse`/`renderSearch`. Used by tests that exercise those helpers
 * directly so their assertions are isolated from the initial render's output.
 */
export async function setupCleared(options: { hash?: string } = {}): Promise<SetupCtx> {
  const ctx = setup(options);
  await flush();
  ctx.results.innerHTML = '';
  return ctx;
}

/* ===========================================================================
 * Table-traversal helpers (browser-agnostic; work on Element).
 * ========================================================================= */

export function dataRows(table: Element): Element[] {
  return Array.from(table.querySelectorAll('tbody tr'));
}
export function rowByName(table: Element, name: string): Element | undefined {
  return dataRows(table).find((tr) => (tr.querySelector('td')?.textContent ?? '').trim() === name);
}
export function cellsOf(row: Element): Element[] {
  return Array.from(row.querySelectorAll('td'));
}
export function clickNameLink(row: Element): void {
  const nameCell = cellsOf(row)[0];
  const link = nameCell.querySelector('a, button') as HTMLElement | null;
  (link ?? (nameCell as HTMLElement)).click();
}
export function buttonsByText(container: Element, text: string): HTMLButtonElement[] {
  return Array.from(container.querySelectorAll('button')).filter(
    (b) => (b.textContent ?? '').trim() === text,
  );
}

/* ===========================================================================
 * Shared per-test fetch stub lifecycle
 *
 * `fetchMock` is an `export let` live binding: `installAppTestLifecycle()`'s
 * `beforeEach` rebinds it to a fresh permissive `vi.fn` each test, and every
 * importer sees the rebound value (ESM live bindings — verified against this
 * vitest setup). Tests therefore read `fetchMock.mock.calls` exactly as the
 * monolith did, with no per-file `let fetchMock` declaration.
 * ========================================================================= */

export let fetchMock: ReturnType<typeof vi.fn> = vi.fn(async () => mockResponse({ body: {} }));

/**
 * Register the shared `beforeEach` (permissive default fetch stub) and
 * `afterEach` (DOM + mock cleanup) used by every split app test file. Call
 * exactly once at module top level in each `*.test.ts`.
 */
export function installAppTestLifecycle(): void {
  beforeEach(() => {
    // A permissive default: every browse/search GET returns a recognizable
    // result derived from the requested path/query, and every mutation returns
    // 200. Individual tests override with `fetchMock.mockImplementation(...)`
    // or `.mockResolvedValueOnce(...)` for specific scenarios. This also means
    // incidental background renders (e.g. from accumulated hashchange
    // listeners) never throw unhandled rejections.
    fetchMock = vi.fn(async (url: string, init?: RequestInit) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/browse')) {
        const raw = u.split('path=')[1] ?? '';
        const path = decodeURIComponent(raw);
        const childName = 'child-of-' + (path || 'root');
        return mockResponse({
          body: browseResult({
            path,
            entries: [fileEntry({ name: childName, path: joinPathHelper(path, childName) })],
            fileCount: 1,
            totalSize: 10,
          }),
        });
      }
      if (method === 'GET' && u.includes('/search')) {
        const afterQuery = u.slice(u.indexOf('query=') + 6);
        const query = decodeURIComponent(afterQuery.split('&')[0]);
        return mockResponse({
          body: {
            query,
            path: '',
            results: [
              fileEntry({
                name: 'result-for-' + query,
                path: joinPathHelper('docs', 'result-for-' + query),
              }),
            ],
          } as SearchResult,
        });
      }
      return mockResponse({ status: 200, body: {} });
    });
    vi.stubGlobal('fetch', fetchMock);
  });

  afterEach(() => {
    // NOTE: do NOT touch window.location.hash here. In happy-dom, assigning to
    // location.hash dispatches `hashchange` synchronously. startApp unsubscribes
    // the previous mount's render() listener on re-mount (so listeners no longer
    // accumulate across tests), but the CURRENT test's listener remains active
    // until the next test's setup() re-mounts. Resetting the hash after
    // `vi.unstubAllGlobals()` would therefore drive a render through the REAL
    // fetch. We clear the body first (while fetch is still stubbed, so any
    // in-flight render's already-issued request stays mocked) and reset the hash
    // at the start of the next test's setup() instead.
    document.body.innerHTML = '';
    vi.unstubAllGlobals();
    vi.restoreAllMocks();
  });
}

/**
 * Shared services for the file-browser app modules.
 *
 * The file-browser is split across several focused modules (dom-builders,
 * render-browse, render-search, toolbar-handlers, render-orchestrator). They
 * all need access to three cross-cutting things that `startApp` establishes
 * once per mount:
 *
 *   - the {@link ApiClient} singleton (used for fetches and download URLs);
 *   - the DOM element refs the render helpers write into (results, status,
 *     breadcrumb, search input);
 *   - a "render hook" that action-button handlers and the upload handler call
 *     to trigger a fresh route dispatch (used instead of importing the
 *     orchestrator directly, which would create a module cycle: orchestrator →
 *     render-browse → dom-builders → orchestrator).
 *
 * Centralizing them here keeps the cross-module dependency graph acyclic and
 * makes the re-bind-on-remount contract explicit — replacing the bare
 * module-level `let resultsEl!: HTMLElement` variables that used to live in
 * `app.ts`. `render-orchestrator.init` re-binds the refs every mount, so the
 * render helpers always target the most recently mounted app.
 */
import { ApiClient } from '../api.js';

/** The DOM element refs established by each `startApp` mount. */
export interface DomRefs {
  results: HTMLElement;
  status: HTMLElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
}

/* -------------------------------------------------------------------------
 * API singleton
 *
 * Created once at module load, exactly as the original `app.ts` created
 * `const api = new ApiClient();` at its top level. The constructor performs
 * no I/O, so creating it before `fetch` is stubbed in a test is safe.
 * ---------------------------------------------------------------------- */
const api = new ApiClient();

/** The shared API client (used for fetches and download-URL construction). */
export function getApi(): ApiClient {
  return api;
}

/* -------------------------------------------------------------------------
 * DOM refs — rebound by `render-orchestrator.init` on every `startApp` mount
 * so `renderBrowse` / `renderSearch` always target the most recent mount.
 *
 * The definite-assignment assertions mirror the original `let resultsEl!:
 * HTMLElement` pattern: the refs are uninitialized only until the first
 * `init()` call, which always runs before any render helper reads them.
 * ---------------------------------------------------------------------- */
let results!: HTMLElement;
let status!: HTMLElement;
let breadcrumb!: HTMLElement;
let searchInput!: HTMLInputElement;

/** Bind the DOM refs for the current mount. Called from the orchestrator's `init`. */
export function setRefs(refs: DomRefs): void {
  results = refs.results;
  status = refs.status;
  breadcrumb = refs.breadcrumb;
  searchInput = refs.searchInput;
}

export function getResults(): HTMLElement {
  return results;
}

export function getStatus(): HTMLElement {
  return status;
}

export function getBreadcrumb(): HTMLElement {
  return breadcrumb;
}

export function getSearchInput(): HTMLInputElement {
  return searchInput;
}

/* -------------------------------------------------------------------------
 * Render hook
 *
 * Action-button handlers (in dom-builders) and the upload handler (in
 * toolbar-handlers) call `rerender()` to trigger a fresh route dispatch. They
 * cannot import `render` from render-orchestrator.ts directly without creating
 * the cycle noted above, so the orchestrator registers its `render` function
 * here during `init` and the callers invoke it indirectly through `rerender`.
 * ---------------------------------------------------------------------- */
let renderHook: () => Promise<void> = async () => {};

/** Register the route-dispatching render function. */
export function setRenderHook(fn: () => Promise<void>): void {
  renderHook = fn;
}

/** Trigger a fresh render via the registered hook. No-op until `setRenderHook` is called. */
export function rerender(): Promise<void> {
  return renderHook();
}

/**
 * Builds a minimal fetch `Response` stand-in for the mocked global `fetch`.
 *
 * `text()` returns the raw text (defaults to the JSON-stringified body).
 * `json()` returns the parsed body when one is provided; otherwise it falls
 * back to parsing `text` as JSON (when only `text` was given), and finally to
 * an empty object. `ok` is derived from `status` (true for any 2xx) unless an
 * explicit `ok` is supplied, in which case it wins.
 *
 * This is the UNION of the two previously-inline helpers that lived in
 * `src/api.test.ts` and `src/app.test.ts`. They were identical except in the
 * `json()` fallback for the text-only case: the `app` copy returned `{}`,
 * whereas the `api` copy parsed the text as JSON. Parsing is the more
 * permissive behavior (a strict superset) and is preserved here so every
 * existing call site keeps working. (No call site actually relies on this
 * branch: on the error path `ApiClient.request` only reads `.text()`, and on
 * the success path a `body` is always supplied.) The behavior is pinned by the
 * `mockResponse helper` characterization suite in `src/api.test.ts`.
 *
 * Test-only utility: deliberately kept out of the production `tsc` build via
 * the `src/test-utils/**` glob in `tsconfig.json`'s `exclude` array, so it is
 * never shipped to `wwwroot/dist`. Only test files import it.
 */
export interface MockResponseOptions {
  ok?: boolean;
  status?: number;
  body?: unknown;
  text?: string;
}

export function mockResponse(opts: MockResponseOptions): Response {
  const status = opts.status ?? 200;
  const ok = opts.ok ?? (status >= 200 && status < 300);
  const text = opts.text ?? JSON.stringify(opts.body ?? {});
  return {
    ok,
    status,
    text: async () => text,
    json: async () => opts.body ?? (opts.text ? JSON.parse(opts.text) : {}),
  } as unknown as Response;
}
----- API -----
export interface FileEntry {
  name: string;
  path: string;
  isDirectory: boolean;
  size: number;
  lastModified: string;
  /** Immediate-child count (files + folders) for directories; 0 for files. */
  itemCount?: number;
}

export interface BrowseResult {
  path: string;
  parent: string | null;
  entries: FileEntry[];
  folderCount: number;
  fileCount: number;
  totalSize: number;
}

export interface SearchResult {
  query: string;
  path: string;
  results: FileEntry[];
}

export class ApiClient {
  constructor(private readonly baseUrl: string = '/api/files') {}

  async browse(path: string): Promise<BrowseResult> {
    return this.request<BrowseResult>(`${this.baseUrl}/browse?path=${encodeURIComponent(path)}`, {
      method: 'GET',
    });
  }

  async search(query: string, path: string): Promise<SearchResult> {
    return this.request<SearchResult>(
      `${this.baseUrl}/search?query=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`,
      { method: 'GET' },
    );
  }

  async upload(path: string, file: File): Promise<{ path: string }> {
    const formData = new FormData();
    formData.append('file', file);
    return this.request<{ path: string }>(
      `${this.baseUrl}/upload?path=${encodeURIComponent(path)}`,
      { method: 'POST', body: formData },
    );
  }

  async delete(path: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/delete?path=${encodeURIComponent(path)}`, {
      method: 'DELETE',
    });
  }

  async move(source: string, destination: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/move`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
    });
  }

  async copy(source: string, destination: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/copy`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
    });
  }

  async createDirectory(path: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/mkdir?path=${encodeURIComponent(path)}`, {
      method: 'POST',
    });
  }

  downloadUrl(path: string): string {
    return `${this.baseUrl}/download?path=${encodeURIComponent(path)}`;
  }

  private async request<T>(url: string, init?: RequestInit): Promise<T> {
    const res = await fetch(url, init);
    if (!res.ok) {
      throw new Error(res.status + ': ' + (await res.text()));
    }
    return (await res.json()) as T;
  }
}

