async function fakePick(filesChosen: File[] | null, focusAfter: boolean): Promise<File[]> {
  const input = document.createElement('input');
  (input as any).type = 'file';
  document.body.append(input);
  if (filesChosen) {
    const dt = new DataTransfer();
    for (const f of filesChosen) dt.items.add(f);
    (input as any).files = dt.files;
  }
  const result = await new Promise<File[]>((resolve) => {
    let settled = false;
    const finish = (list: File[]): void => {
      if (settled) return;
      settled = true;
      window.removeEventListener('focus', onFocus);
      resolve(list);
    };
    const onFocus = (): void => {
      setTimeout(
        () => finish((input as any).files && (input as any).files.length > 0 ? Array.from((input as any).files) : []),
