    // fallback, the window regaining focus signals the picker was dismissed.
    // A short delay lets a real `change` win first if files were selected;
    // finish()'s `settled` guard makes any later focus a no-op.
    const onFocus = (): void => {
      setTimeout(
        () => finish(input.files && input.files.length > 0 ? Array.from(input.files) : []),
